31→  const [isGeneratingSolution, setIsGeneratingSolution] = useState(false);
32→  const [generatedSolution, setGeneratedSolution] = useState<GeneratedSolution | null>(null);
33→
34→  // Checked recommendations for projected score
35→  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
36→
37→  // ═══ VAULT — Système "Generate All, Reveal on Credit" ═══
38→  const auditId = data?.timestamp || 'current';
39→  const [vaultBlocks, setVaultBlocks] = useState<ContentBlock[]>([]);
40→  const [vaultSummary, setVaultSummary] = useState<VaultSummary | null>(null);
41→  const [vaultReloadKey, setVaultReloadKey] = useState(0);
42→
43→  // Charger les blocs depuis le vault
44→  useEffect(() => {
45→    if (!data) return;
46→    const loadedBlocks = getContentBlocks(auditId);
47→    setVaultBlocks(loadedBlocks);
48→    if (loadedBlocks.length > 0) {
49→      setVaultSummary(getVaultSummary(auditId));
50→    }
51→  }, [auditId, data, vaultReloadKey]);
52→
53→  // Gérer le déblocage d'un bloc individuel
54→  const handleUnlockBlock = useCallback((blockId: string) => {
55→    const success = onDeductCredits(1);
56→    if (!success) return;
57→    unlockContent(auditId, blockId);
58→    setVaultReloadKey(prev => prev + 1);
59→  }, [auditId, onDeductCredits]);
