16→const Analyze: React.FC<AnalyzeProps> = ({ onAnalyze, isAnalyzing }) => {
17→  const [inputUrl, setInputUrl] = useState('');
18→  const [currentStep, setCurrentStep] = useState(0);
19→
20→  useEffect(() => {
21→    if (!isAnalyzing) { setCurrentStep(0); return; }
22→    let step = 0;
23→    setCurrentStep(0);
24→    const timers: ReturnType<typeof setTimeout>[] = [];
25→    let accumulated = 0;
26→    analysisSteps.forEach((s, i) => {
27→      if (i > 0) {
28→        accumulated += analysisSteps[i - 1].duration;
29→        timers.push(setTimeout(() => setCurrentStep(i), accumulated));
30→      }
31→    });
32→    return () => timers.forEach(clearTimeout);
33→  }, [isAnalyzing]);
34→
35→  const handleSubmit = (e: React.FormEvent) => {
36→    e.preventDefault();
37→    if (inputUrl && !isAnalyzing) {
38→      onAnalyze(inputUrl);
39→    }
